    82→// ─── Issue Card Dialog ─────────────────────────────────────
    83→function IssueCardDialog({ reg }: { reg: Registration }) {
    84→  const [open, setOpen] = useState(false);
    85→  const [validFrom, setValidFrom] = useState(() => new Date().toISOString().split("T")[0]);
    86→  const [validUntil, setValidUntil] = useState(() => {
    87→    const d = new Date(); d.setFullYear(d.getFullYear() + 1);
    88→    return d.toISOString().split("T")[0];
    89→  });
    90→  const [loading, setLoading] = useState(false);
    91→  const [qrDataUrl, setQrDataUrl] = useState<string | null>(null);
    92→  const { toast } = useToast();
    93→  const queryClient = useQueryClient();
    94→
    95→  const handleIssue = async () => {
    96→    setLoading(true);
    97→    try {
    98→      const res = await apiRequest("POST", `/api/admin/registrations/${reg.id}/issue-card`, { validFrom, validUntil });
    99→      const data = await res.json();
   100→      setQrDataUrl(data.qrDataUrl);
   101→      queryClient.invalidateQueries({ queryKey: ["/api/admin/registrations"] });
   102→      toast({ title: "Card Issue ਹੋ ਗਿਆ ✓", description: `Card No: ${data.registration.cardNumber}` });
   103→    } catch {
   104→      toast({ title: "ਗਲਤੀ", description: "Card issue ਕਰਨ ਵਿੱਚ ਸਮੱਸਿਆ", variant: "destructive" });
   105→    } finally {
   106→      setLoading(false);
   107→    }
   108→  };
   109→
   110→  const downloadQR = () => {
   111→    if (!qrDataUrl) return;
   112→    const a = document.createElement("a");
   113→    a.href = qrDataUrl;
   114→    a.download = `QR-${reg.cardNumber || reg.name}.png`;
   115→    a.click();
   116→  };
   117→
   118→  const downloadQRFromServer = async () => {
   119→    const res = await fetch(`/api/admin/registrations/${reg.id}/qr`, { credentials: "include" });
   120→    const blob = await res.blob();
   121→    const url = URL.createObjectURL(blob);
   122→    const a = document.createElement("a");
   123→    a.href = url;
   124→    a.download = `QR-${reg.cardNumber || reg.name}.png`;
   125→    a.click();
   126→    URL.revokeObjectURL(url);
   127→  };
   128→
   129→  return (
   130→    <Dialog open={open} onOpenChange={setOpen}>
   131→      <DialogTrigger asChild>
   132→        <Button size="sm" variant="outline" className="gap-1.5 text-green-700 border-green-300 hover:bg-green-50" data-testid={`button-issue-${reg.id}`}>
   133→          <QrCode className="h-3.5 w-3.5" /> QR Card
   134→        </Button>
   135→      </DialogTrigger>
   136→      <DialogContent className="max-w-md">
   137→        <DialogHeader>
   138→          <DialogTitle className="flex items-center gap-2">
   139→            <QrCode className="h-5 w-5 text-green-700" /> Card Issue ਕਰੋ
   140→          </DialogTitle>
   141→        </DialogHeader>
   142→
   143→        <div className="space-y-4">
   144→          {/* Member Info */}
   145→          <div className="bg-muted/40 rounded-lg p-3 flex items-center gap-3">
   146→            <Avatar className="h-12 w-12">
   147→              {reg.photoUrl ? <AvatarImage src={reg.photoUrl} /> : reg.photoData ? <AvatarImage src={`data:${reg.photoMimeType};base64,${reg.photoData}`} /> : null}
   148→              <AvatarFallback>{reg.name[0]}</AvatarFallback>
   149→            </Avatar>
   150→            <div>
   151→              <p className="font-semibold">{reg.name}</p>
   152→              <p className="text-sm text-muted-foreground">{reg.designation} — {reg.village}, {reg.district}</p>
   153→              {reg.cardNumber && <p className="text-xs font-mono text-green-700 mt-0.5">{reg.cardNumber}</p>}
   154→            </div>
   155→          </div>
   156→
   157→          {/* Validity Dates */}
   158→          <div className="grid grid-cols-2 gap-3">
   159→            <div className="space-y-1.5">
   160→              <Label className="text-xs">Valid From</Label>
   161→              <Input type="date" value={validFrom} onChange={(e) => setValidFrom(e.target.value)} />
   162→            </div>
   163→            <div className="space-y-1.5">
   164→              <Label className="text-xs">Valid Until</Label>
   165→              <Input type="date" value={validUntil} onChange={(e) => setValidUntil(e.target.value)} />
   166→            </div>
   167→          </div>
   168→
   169→          <Button onClick={handleIssue} disabled={loading} className="w-full">
   170→            {loading ? <><Loader2 className="mr-2 h-4 w-4 animate-spin" />QR ਬਣ ਰਿਹਾ ਹੈ...</> : "Card Issue ਕਰੋ ਅਤੇ QR ਬਣਾਓ"}
   171→          </Button>
   172→
   173→          {/* QR Result */}
   174→          {qrDataUrl && (
   175→            <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }}
   176→              className="border-2 border-green-300 rounded-xl p-4 text-center bg-green-50">
   177→              <CheckCircle className="h-5 w-5 text-green-600 mx-auto mb-2" />
   178→              <img src={qrDataUrl} alt="QR Code" className="w-40 h-40 mx-auto rounded-lg mb-3" />
   179→              <p className="text-xs text-muted-foreground mb-3">ਇਹ QR Code ਪ੍ਰਿੰਟ ਕੀਤੇ Card ਤੇ ਲਗਾਓ</p>
   180→              <Button onClick={downloadQR} variant="default" size="sm" className="w-full">
   181→                <Download className="mr-2 h-4 w-4" /> QR PNG ਡਾਊਨਲੋਡ ਕਰੋ
   182→              </Button>
   183→            </motion.div>
   184→          )}
   185→
   186→          {/* Download QR for already-issued cards */}
   187→          {!qrDataUrl && reg.cardNumber && reg.validUntil && (
   188→            <div className="border rounded-xl p-3 text-center bg-muted/30">
   189→              <div className="flex items-center justify-center gap-2 mb-2 text-sm text-muted-foreground">
   190→                <Calendar className="h-4 w-4" />
   191→                {reg.validUntil && new Date(reg.validUntil) < new Date()
   192→                  ? <span className="text-orange-600 flex items-center gap-1"><AlertTriangle className="h-3.5 w-3.5" />Expired</span>
   193→                  : <span className="text-green-700">Valid till {new Date(reg.validUntil).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" })}</span>}
   194→              </div>
   195→              <Button onClick={downloadQRFromServer} variant="outline" size="sm" className="w-full">
   196→                <QrCode className="mr-2 h-4 w-4" /> ਪੁਰਾਣਾ QR ਡਾਊਨਲੋਡ ਕਰੋ
   197→              </Button>
   198→            </div>
   199→          )}
   200→        </div>
   201→      </DialogContent>
   202→    </Dialog>
   203→  );
   204→}
