              <Button type="submit" className="w-full" disabled={isLoggingIn} data-testid="button-login">
                {isLoggingIn ? <><Loader2 className="mr-2 h-4 w-4 animate-spin" />ਲੌਗਇਨ ਹੋ ਰਿਹਾ ਹੈ...</> : "ਲੌਗਇਨ ਕਰੋ"}
