                <Input type="date" value={validUntil} onChange={(e) => setValidUntil(e.target.value)} />
              </div>
            </div>
          </div>

          <Button onClick={handleIssue} disabled={loading} className="w-full bg-green-600 hover:bg-green-700">
            {loading
