              : <><QrCode className="mr-2 h-4 w-4" />Card Issue ਕਰੋ ਅਤੇ QR ਬਣਾਓ</>}
          </Button>

          {qrDataUrl && (
            <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }}
