              <img src={qrDataUrl} alt="QR Code" className="w-44 h-44 mx-auto rounded-lg mb-3 border border-green-200" />
              <p className="text-xs text-muted-foreground mb-3">ਇਹ QR Code ਪ੍ਰਿੰਟ ਕੀਤੇ Card ਤੇ ਲਗਾਓ</p>
